                    const ScalarizerPassOptions &Options)
      : DT(dt), TTI(tti), ScalarizeVariableInsertExtract(Options.ScalarizeVariableInsertExtract),
        ScalarizeLoadStore(Options.ScalarizeLoadStore),
        MinVectorWidth(Options.MinVectorWidth),
        MaxVectorWidth(Options.MaxVectorWidth) {}

