  bool scalarize(Instruction *I);

  // Return a scattered form of V.  If new instructions are needed,
  // insert them before I.
  Scatterer scatter(Instruction *I, Value *V, const VectorSplit &VS);

  // Record in Gathered that instruction I has been replaced by the
  // scattered values in CV.
  void gather(Instruction *I, const ValueVector &CV, const VectorSplit &VS);

  // Return a value that represents the scattered form of vector type VT
  // loaded from Ptr.  The scattered form is a vector of pointers,
  // one for each fragment.
  std::optional<VectorLayout> getVectorLayout(Type *VT, Align Alignment,
