  // Return a description of how to split vector type VT.
  std::optional<VectorSplit> getVectorSplit(Type *VT) const;

  // Split a select instruction.
  bool splitSelect(SelectInst &SI);

  // Split a call instruction.
  bool splitCall(CallInst &CI);

  // Split a unary operation.
  template <typename T> bool splitUnary(Instruction &I, T Splitter);

  // Split a binary operation.
  template <typename T> bool splitBinary(Instruction &I, T Splitter);

  // Split a cast operation.
  bool splitCast(CastInst &CI);

  // Replace all uses of instruction I with a scalarized equivalent.
  // The scalarized form is in CV.
  void replaceUses(Instruction *I, const ValueVector &CV,
