  // Replace all uses of instruction I with value V.
  void replaceUses(Instruction *I, Value *V);

  // Return true if I has been scalarized.
  bool isScalarized(Instruction *I) const;

  // Mark I as having been scalarized.
  void scalarized(Instruction *I);

  // Perform the final replacement of scalarized instructions.  Return
  // true if the function was changed.
  bool finish();

