  // Instructions that have been scalarized and that will be replaced
  // at the end of the pass.
  GatherList Gathered;

  // Instructions that have been scalarized and should be deleted at the
  // end of the pass.
  SmallPtrSet<Instruction *, 16> Scalarized;

  // Instructions that can be deleted after all replacements are done.
  SmallVector<Instruction *, 16> PotentiallyDeadInstrs;
};

