                    const ScalarizerPassOptions &Options)
      : DT(dt), TTI(tti), ScalarizeVariableInsertExtract(Options.ScalarizeVariableInsertExtract),
        ScalarizeLoadStore(Options.ScalarizeLoadStore),
        MinVectorWidth(Options.MinVectorWidth),
        MaxVectorWidth(Options.MaxVectorWidth) {}

  // The main entry point.  Returns true if the function was changed.
  bool visit(Function &F);

  // InstVisitor methods.  They return true if the instruction was scalarized,
  // false otherwise.
  bool visitInstruction(Instruction &I);
  bool visitCastInst(CastInst &CI);
  bool visitBinaryOperator(BinaryOperator &BO);
  bool visitCmpInst(CmpInst &CI);
  bool visitSelectInst(SelectInst &SI);
  bool visitBitCastInst(BitCastInst &BCI);
  bool visitInsertElementInst(InsertElementInst &IEI);
  bool visitExtractValueInst(ExtractValueInst &EVI);
  bool visitExtractElementInst(ExtractElementInst &EEI);
  bool visitShuffleVectorInst(ShuffleVectorInst &SVI);
  bool visitPHINode(PHINode &PHI);
  bool visitLoadInst(LoadInst &LI);
  bool visitStoreInst(StoreInst &SI);
  bool visitCallInst(CallInst &CI);
  bool visitFreezeInst(FreezeInst &FI);

private:
  // Try to scalarize a single instruction.  Return true if successful.
  bool scalarize(Instruction *I);

  // Return a scattered form of V.  If new instructions are needed,
  // insert them before I.
  Scatterer scatter(Instruction *I, Value *V, const VectorSplit &VS);

