Scatterer::Scatterer(BasicBlock *bb, BasicBlock::iterator bbi, Value *v,
                     const VectorSplit &vs, ValueVector *cachePtr)
    : BB(bb), BBI(bbi), V(v), VS(vs), IsPointer(v->getType()->isPointerTy()),
      CachePtr(cachePtr) {
  if (CachePtr) {
    if (!CachePtr->empty())
      return;
    CachePtr->resize(VS.NumFragments);
  } else {
    Tmp.resize(VS.NumFragments);
    CachePtr = &Tmp;
  }
}

Value *Scatterer::operator[](unsigned Frag) {
  assert(Frag < VS.NumFragments && "Fragment index out of range");
  if ((*CachePtr)[Frag])
    return (*CachePtr)[Frag];

  IRBuilder<> Builder(BB, BBI);
  if (IsPointer) {
    Type *Ty = V->getType();
    Type *ElementTy = Ty->getPointerElementType();
    if (auto *VecTy = dyn_cast<VectorType>(ElementTy)) {
      Type *FragTy = VS.getFragmentType(Frag);
      Type *FragPtrTy = FragTy->getPointerTo(Ty->getPointerAddressSpace());
      unsigned ElementSize =
          V->getType()->getPointerElementType()->getPrimitiveSizeInBits() / 8;
      Value *Idx = Builder.getInt64(Frag * VS.NumPacked * ElementSize);
      Value *GEP = Builder.CreateGEP(Builder.getInt8Ty(), V, Idx);
      Value *BC = Builder.CreateBitCast(GEP, FragPtrTy);
      return ((*CachePtr)[Frag] = BC);
    }
  }

  if (isa<UndefValue>(V))
    return ((*CachePtr)[Frag] = UndefValue::get(VS.getFragmentType(Frag)));

  if (isa<PoisonValue>(V))
    return ((*Cache_Ptr)[Frag] = PoisonValue::get(VS.getFragmentType(Frag)));

  if (auto *C = dyn_cast<Constant>(V)) {
    if (auto *S = dyn_cast<ConstantDataVector>(C)) {
      unsigned NumElts = VS.getFragmentType(Frag)->getVectorNumElements();
      SmallVector<Constant *, 16> SubElts;
      for (unsigned I = 0; I < NumElts; ++I)
        SubElts.push_back(S->getElementAsConstant(Frag * VS.NumPacked + I));
      return ((*CachePtr)[Frag] = ConstantVector::get(SubElts));
    }
    if (isa<ConstantVector>(C) || isa<ConstantAggregateZero>(C)) {
      unsigned NumElts = VS.getFragmentType(Frag)->getVectorNumElements();
      SmallVector<Constant *, 16> SubElts;
      for (unsigned I = 0; I < NumElts; ++I)
        SubElts.push_back(C->getAggregateElement(Frag * VS.NumPacked + I));
      return ((*CachePtr)[Frag] = ConstantVector::get(SubElts));
    }
  }

  assert(VS.NumPacked > 1 && "Cannot extract from a scalar");
  unsigned RemElts = VS.VecTy->getElementCount().getFixedValue() % VS.NumPacked;
  if (RemElts != 0 && Frag == VS.NumFragments - 1) {
    // This is a remainder.  The last fragment is shorter than the others.
    // Since we can't create a vector of a different size, we need to create
    // a vector of the original size and then shrink it.
    int Mask[VS.NumPacked];
    for (unsigned i = 0; i < RemElts; ++i)
      Mask[i] = Frag * VS.NumPacked + i;
    for (unsigned i = RemElts; i < VS.NumPacked; ++i)
      Mask[i] = -1;
    Value *SV = Builder.CreateShuffleVector(V, V, Mask,
                                            V->getName() + ".s" + Twine(Frag));
    return ((*CachePtr)[Frag] = Builder.CreateVectorTrunc(
                SV, VS.getFragmentType(Frag),
                V->getName() + ".t" + Twine(Frag)));
  }

  int Mask[VS.NumPacked];
  for (unsigned i = 0; i < VS.NumPacked; ++i)
    Mask[i] = Frag * VS.NumPacked + i;
  return ((*CachePtr)[Frag] = Builder.CreateShuffleVector(
              V, V, Mask, V->getName() + ".s" + Twine(Frag)));
}

