bool ScalarizerVisitor::visit(Function &F) {
  assert(Scattered.empty() && Gathered.empty() && Scalarized.empty());
  for (BasicBlock *BB : post_order(&F))
    for (Instruction &I : *BB)
      scalarize(&I);
  return finish();
}

bool ScalarizerVisitor::scalarize(Instruction *I) {
  if (isScalarized(I))
    return true;
  if (visit(*I)) {
    scalarized(I);
    return true;
  }
  return false;
}

Scatterer ScalarizerVisitor::scatter(Instruction *I, Value *V,
                                     const VectorSplit &VS) {
  auto It = Scattered.find({V, VS.SplitTy});
  if (It != Scattered.end())
    return Scatterer(I->getParent(), I->getIterator(), V, VS, &It->second);

  if (auto *AI = dyn_cast<Argument>(V)) {
    auto &Cache = Scattered[{V, VS.SplitTy}];
    return Scatterer(I->getParent(), I->getIterator(), AI, VS, &Cache);
  }
  if (auto *LI = dyn_cast<Instruction>(V)) {
    if (scalarize(LI)) {
      auto It = Scattered.find({V, VS.SplitTy});
      assert(It != Scattered.end() && "Operand not scattered");
      return Scatterer(I->getParent(), I->getIterator(), V, VS, &It->second);
    }
  }

  auto &Cache = Scattered[{V, VS.SplitTy}];
  return Scatterer(I->getParent(), I->getIterator(), V, VS, &Cache);
}

void ScalarizerVisitor::gather(Instruction *I, const ValueVector &CV,
                               const VectorSplit &VS) {
  Scattered.insert({{I, VS.SplitTy}, CV});
  Gathered.push_back({I, &Scattered.find({I, VS.SplitTy})->second});
}

