std::optional<VectorSplit> ScalarizerVisitor::getVectorSplit(Type *VT) const {
  auto *VecTy = dyn_cast<FixedVectorType>(VT);
  if (!VecTy)
    return std::nullopt;

  unsigned NumElts = VecTy->getNumElements();
  if (NumElts == 0)
    return std::nullopt;

  VectorSplit VS;
  VS.VecTy = VecTy;

  if (VecTy->getElementType()->isPointerTy()) {
    VS.NumPacked = 1;
    VS.NumFragments = NumElts;
    VS.SplitTy = VecTy->getElementType();
    return VS;
  }

  unsigned EltBits = VecTy->getElementType()->getPrimitiveSizeInBits();
  if (EltBits == 0)
    return std::nullopt;

  unsigned MaxWidth = MaxVectorWidth;
  if (TTI)
    MaxWidth = TTI->getScalarizationOverhead(VecTy, false, false);

  unsigned MaxBits = std::max(EltBits, MaxWidth);
  VS.NumPacked = MaxBits / EltBits;
  if (VS.NumPacked == 0)
    VS.NumPacked = 1;

  while (VS.NumPacked > 1 && (VS.NumPacked / 2) * EltBits >= MinVectorWidth)
    VS.NumPacked /= 2;

  VS.NumFragments = (NumElts + VS.NumPacked - 1) / VS.NumPacked;
  if (VS.NumFragments == 1)
    return std::nullopt;

  if (VS.NumPacked > 1)
    VS.SplitTy = FixedVectorType::get(VecTy->getElementType(), VS.NumPacked);
  else
    VS.SplitTy = VecTy->getElementType();

  unsigned RemElts = NumElts % VS.NumPacked;
  if (RemElts != 0)
    VS.RemainderTy = FixedVectorType::get(VecTy->getElementType(), RemElts);

  return VS;
}

void ScalarizerVisitor::replaceUses(Instruction *I, Value *V) {
  if (I != V) {
    I->replaceAllUsesWith(V);
    PotentiallyDeadInstrs.emplace_back(I);
  }
}

void ScalarizerVisitor::replaceUses(Instruction *I, const ValueVector &CV,
                                    const VectorSplit &VS) {
  if (I->use_empty())
    return;

  IRBuilder<> Builder(I->getParent(), skipPastPhiNodesAndDbg(I->getIterator()));
  Value *V = concatenate(Builder, CV, VS, I->getName());
  replaceUses(I, V);
}

bool ScalarizerVisitor::isScalarized(Instruction *I) const {
  return Scalarized.count(I);
}

void ScalarizerVisitor::scalarized(Instruction *I) {
  Scalarized.insert(I);
}

bool ScalarizerVisitor::visitInstruction(Instruction &I) {
  return false;
