template <typename T>
bool ScalarizerVisitor::splitUnary(Instruction &I, T Splitter) {
  std::optional<VectorSplit> VS = getVectorSplit(I.getType());
  if (!VS)
    return false;

  IRBuilder<> Builder(&I);
  Scatterer Op0 = scatter(&I, I.getOperand(0), *VS);
  ValueVector Res;
  Res.resize(VS->NumFragments);

  for (unsigned I = 0; I < VS->NumFragments; ++I)
    Res[I] = Splitter(Builder, Op0[I], I.getName() + ".i" + Twine(I));

  gather(&I, Res, *VS);
  return true;
}

template <typename T>
bool ScalarizerVisitor::splitBinary(Instruction &I, T Splitter) {
  std::optional<VectorSplit> VS = getVectorSplit(I.getType());
  if (!VS)
    return false;

  IRBuilder<> Builder(&I);
  Scatterer Op0 = scatter(&I, I.getOperand(0), *VS);
  Scatterer Op1 = scatter(&I, I.getOperand(1), *VS);
  ValueVector Res;
  Res.resize(VS->NumFragments);

  for (unsigned I = 0; I < VS->NumFragments; ++I)
    Res[I] = Splitter(Builder, Op0[I], Op1[I], I.getName() + ".i" + Twine(I));

  gather(&I, Res, *VS);
  return true;
}

bool ScalarizerVisitor::splitCast(CastInst &CI) {
  std::optional<VectorSplit> VS = getVectorSplit(CI.getDestTy());
  if (!VS)
    return false;

  IRBuilder<> Builder(&CI);
  Scatterer Op0 = scatter(&CI, CI.getOperand(0), *VS);
  ValueVector Res;
  Res.resize(VS->NumFragments);

  for (unsigned I = 0; I < VS->NumFragments; ++I)
    Res[I] = Builder.CreateCast(CI.getOpcode(), Op0[I],
                                VS->getFragmentType(I),
                                CI.getName() + ".i" + Twine(I));

  gather(&CI, Res, *VS);
  return true;
}

bool ScalarizerVisitor::visitCastInst(CastInst &CI) {
  return splitCast(CI);
}

bool ScalarizerVisitor::visitBinaryOperator(BinaryOperator &BO) {
  return splitBinary(BO,
                     [&BO](IRBuilder<> &Builder, Value *Op0, Value *Op1,
                           const Twine &Name) {
                       Value *V = Builder.CreateBinOp(BO.getOpcode(), Op0, Op1, Name);
                       if (auto *NewBO = dyn_cast<BinaryOperator>(V))
                         NewBO->copyIRFlags(&BO);
                       return V;
                     });
}

bool ScalarizerVisitor::visitCmpInst(CmpInst &CI) {
  if (isa<FCmpInst>(CI))
    return splitBinary(CI, FCmpSplitter(cast<FCmpInst>(CI)));
  return splitBinary(CI, ICmpSplitter(cast<ICmpInst>(CI)));
}

bool ScalarizerVisitor::visitSelectInst(SelectInst &SI) {
  return splitSelect(SI);
}

bool ScalarizerVisitor::splitSelect(SelectInst &SI) {
  std::optional<VectorSplit> VS = getVectorSplit(SI.getType());
  if (!VS)
    return false;

  IRBuilder<> Builder(&SI);
  Value *Cond = SI.getCondition();
  Scatterer Op1 = scatter(&SI, SI.getTrueValue(), *VS);
  Scatterer Op2 = scatter(&SI, SI.getFalseValue(), *VS);
  ValueVector Res;
  Res.resize(VS->NumFragments);

  if (Cond->getType()->isVectorTy()) {
    Scatterer CondS = scatter(&SI, Cond, *VS);
    for (unsigned I = 0; I < VS->NumFragments; ++I)
      Res[I] = Builder.CreateSelect(CondS[I], Op1[I], Op2[I],
                                    SI.getName() + ".i" + Twine(I));
  } else {
    for (unsigned I = 0; I < VS->NumFragments; ++I)
      Res[I] = Builder.CreateSelect(Cond, Op1[I], Op2[I],
                                    SI.getName() + ".i" + Twine(I));
  }

