std::optional<VectorSplit> ScalarizerVisitor::getVectorSplit(Type *VT) const {
  auto *VecTy = dyn_cast<FixedVectorType>(VT);
  if (!VecTy)
    return std::nullopt;

  unsigned NumElts = VecTy->getNumElements();
  if (NumElts == 0)
    return std::nullopt;

  VectorSplit VS;
  VS.VecTy = VecTy;

  if (VecTy->getElementType()->isPointerTy()) {
    VS.NumPacked = 1;
    VS.NumFragments = NumElts;
    VS.SplitTy = VecTy->getElementType();
    return VS;
  }

  unsigned EltBits = VecTy->getElementType()->getPrimitiveSizeInBits();
  if (EltBits == 0)
    return std::nullopt;

  unsigned MaxWidth = MaxVectorWidth;
  if (TTI)
    MaxWidth = TTI->getScalarizationOverhead(VecTy, false, false);

  unsigned MaxBits = std::max(EltBits, MaxWidth);
  VS.NumPacked = MaxBits / EltBits;
  if (VS.NumPacked == 0)
    VS.NumPacked = 1;

  while (VS.NumPacked > 1 && (VS.NumPacked / 2) * EltBits >= MinVectorWidth)
    VS.NumPacked /= 2;

  VS.NumFragments = (NumElts + VS.NumPacked - 1) / VS.NumPacked;
  if (VS.NumFragments == 1)
    return std::nullopt;

  if (VS.NumPacked > 1)
    VS.SplitTy = FixedVectorType::get(VecTy->getElementType(), VS.NumPacked);
  else
    VS.SplitTy = VecTy->getElementType();

  unsigned RemElts = NumElts % VS.NumPacked;
  if (RemElts != 0)
    VS.RemainderTy = FixedVectorType::get(VecTy->getElementType(), RemElts);

  return VS;
}

